import{_ as e,o as a,c as r,a4 as i}from"./chunks/framework.BybBnFXO.js";const b=JSON.parse('{"title":"Cubic (Isometric)","description":"","frontmatter":{"title":"Cubic (Isometric)","crystalSystem":"cubic"},"headers":[],"relativePath":"classification/crystal-systems/cubic.md","filePath":"classification/crystal-systems/cubic.md","lastUpdated":1784177547000}'),d={name:"classification/crystal-systems/cubic.md"};function s(c,t,o,l,n,h){return a(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="cubic-isometric" tabindex="-1">Cubic (Isometric) <a class="header-anchor" href="#cubic-isometric" aria-label="Permalink to &quot;Cubic (Isometric)&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The cubic (also called isometric) system has the highest symmetry of the seven crystal systems. Three axes of equal length intersect at right angles. Cubic crystals are optically isotropic — light travels at the same velocity in every direction, producing no birefringence and no pleochroism. Identification therefore relies on refractive index, specific gravity, and spectroscopic tests.</p><h2 id="crystallographic-parameters" tabindex="-1">Crystallographic Parameters <a class="header-anchor" href="#crystallographic-parameters" aria-label="Permalink to &quot;Crystallographic Parameters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Property</th><th>Value</th></tr></thead><tbody><tr><td>Axial lengths</td><td>a = b = c</td></tr><tr><td>Interaxial angles</td><td>α = β = γ = 90°</td></tr><tr><td>Symmetry tier</td><td>highest</td></tr><tr><td>Optical class</td><td>isotropic</td></tr><tr><td>Optic sign</td><td>none</td></tr><tr><td>Birefringence</td><td>none</td></tr><tr><td>Cleavage</td><td>variable by species</td></tr><tr><td>Habit</td><td>Cubes, octahedra, dodecahedra, granular masses</td></tr></tbody></table><h2 id="notable-gem-species" tabindex="-1">Notable Gem Species <a class="header-anchor" href="#notable-gem-species" aria-label="Permalink to &quot;Notable Gem Species&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Gem</th><th>Refractive Index</th><th>Specific Gravity</th></tr></thead><tbody><tr><td>Diamond</td><td>2.417</td><td>3.52</td></tr><tr><td>Spinel</td><td>1.712–1.762</td><td>3.58–3.65</td></tr><tr><td>Garnet — Almandine</td><td>1.770–1.820</td><td>3.95–4.20</td></tr><tr><td>Garnet — Pyrope</td><td>1.714–1.940</td><td>3.50–3.90</td></tr><tr><td>Sodalite</td><td>1.483</td><td>2.18–2.30</td></tr><tr><td>Fluorite</td><td>1.434</td><td>3.18</td></tr><tr><td><em>See the <a href="./../intro.html">classification overview</a> for all crystal systems.</em></td><td></td><td></td></tr></tbody></table>',7)])])}const p=e(d,[["render",s]]);export{b as __pageData,p as default};
